import common, { api } from '@eclipse-che/common';
import axios from 'axios';

import { dashboardBackendPrefix } from '@/services/backend-client/const';

export async function fetchAiAgentRegistry(): Promise<api.IAiAgentRegistry> {
  try {
    const response = await axios.get(`${dashboardBackendPrefix}/ai-agent-registry`);
    return response.data;
  } catch (e) {
    throw new Error(`Failed to fetch AI agent registry. ${common.helpers.errors.getMessage(e)}`);
  }
}
